class Solution(object):
    def hasGroupsSizeX(self, deck):
        from collections import Counter
        from math import gcd
        from functools import reduce
        if len(deck) < 2:
            return False
        freq = Counter(deck)
        return reduce(gcd, freq.values()) >= 2
